INSERT INTO `wp_amelia_notifications` (`id`,`name`,`customName`,`status`,`type`,`entity`,`time`,`timeBefore`,`timeAfter`,`sendTo`,`subject`,`content`,`translations`,`sendOnlyMe`,`whatsAppTemplate`,`minimumTimeBeforeBooking`) VALUES('1','customer_appointment_approved',NULL,'enabled','email','appointment',NULL,NULL,NULL,'customer','Education Platform: %appointment_status% — %service_name% on %appointment_date% at %appointment_start_time%','<!-- Content --><p>Dear <strong>%customer_full_name%</strong>,</p><p>Your appointment has been <strong>confirmed</strong>. Here are your booking details:</p><table style=\"width:100%; border-collapse:collapse; margin: 16px 0;\">  <tr>    <td style=\"padding: 8px 12px; font-weight:bold; width:40%; background:#f5f5f5;\">Service</td>    <td style=\"padding: 8px 12px;\">%service_name%</td>  </tr>  <tr>    <td style=\"padding: 8px 12px; font-weight:bold; background:#f5f5f5;\">Instructor</td>    <td style=\"padding: 8px 12px;\">%employee_full_name%</td>  </tr>  <tr>    <td style=\"padding: 8px 12px; font-weight:bold; background:#f5f5f5;\">Date &amp; Time</td>    <td style=\"padding: 8px 12px;\">%appointment_date_time%</td>  </tr>  <tr>    <td style=\"padding: 8px 12px; font-weight:bold; background:#f5f5f5;\">Duration</td>    <td style=\"padding: 8px 12px;\">%appointment_duration%</td>  </tr>  <tr>    <td style=\"padding: 8px 12px; font-weight:bold; background:#f5f5f5;\">Status</td>    <td style=\"padding: 8px 12px;\">%appointment_status%</td>  </tr>  <tr>    <td style=\"padding: 8px 12px; font-weight:bold; background:#f5f5f5;\">Location</td>    <td style=\"padding: 8px 12px;\">%location_name% — %location_address%</td>  </tr></table><p>🔗 <strong>Join via Zoom:</strong> <a href=\"%zoom_join_url%\">%zoom_join_url%</a><br><em>(This link becomes active at your scheduled time: %appointment_date_time%)</em></p><p>📅 A calendar invite (.ics file) is attached to this email. Click <strong>\"Add to Calendar\"</strong> to save your session.</p><p>If you need to make any changes to your booking, please use the link below:<br><a href=\"%appointment_cancel_url%\">Manage / Cancel Appointment</a></p><p>If you have any questions, feel free to reach out to us at <a href=\"mailto:%company_email%\">%company_email%</a> or call us at %company_phone%.</p><p>We look forward to seeing you!</p><p>Warm regards,<br><strong>%company_name%</strong><br></p>',NULL,'0',NULL,NULL);
INSERT INTO `wp_amelia_notifications` (`id`,`name`,`customName`,`status`,`type`,`entity`,`time`,`timeBefore`,`timeAfter`,`sendTo`,`subject`,`content`,`translations`,`sendOnlyMe`,`whatsAppTemplate`,`minimumTimeBeforeBooking`) VALUES('2','customer_appointment_pending',NULL,'enabled','email','appointment',NULL,NULL,NULL,'customer','Education Platform: Pending — %service_name% on %appointment_date% at %appointment_start_time%','<p>&lt;p&gt;Dear &lt;strong&gt;%customer_full_name%&lt;/strong&gt;,&lt;/p&gt;</p><p><br></p><p>&lt;p&gt;Thank you for booking with us! Your appointment request has been received and is currently &lt;strong&gt;pending approval&lt;/strong&gt;. You will receive a confirmation email once it has been reviewed.&lt;/p&gt;</p><p><br></p><p>&lt;table style=\"width:100%; border-collapse:collapse; margin: 16px 0;\"&gt;</p><p>&nbsp;&lt;tr&gt;</p><p>&nbsp;&nbsp;&lt;td style=\"padding: 8px 12px; font-weight:bold; width:40%; background:#f5f5f5;\"&gt;Service&lt;/td&gt;</p><p>&nbsp;&nbsp;&lt;td style=\"padding: 8px 12px;\"&gt;%service_name%&lt;/td&gt;</p><p>&nbsp;&lt;/tr&gt;</p><p>&nbsp;&lt;tr&gt;</p><p>&nbsp;&nbsp;&lt;td style=\"padding: 8px 12px; font-weight:bold; background:#f5f5f5;\"&gt;Instructor&lt;/td&gt;</p><p>&nbsp;&nbsp;&lt;td style=\"padding: 8px 12px;\"&gt;%employee_full_name%&lt;/td&gt;</p><p>&nbsp;&lt;/tr&gt;</p><p>&nbsp;&lt;tr&gt;</p><p>&nbsp;&nbsp;&lt;td style=\"padding: 8px 12px; font-weight:bold; background:#f5f5f5;\"&gt;Date &amp;amp; Time&lt;/td&gt;</p><p>&nbsp;&nbsp;&lt;td style=\"padding: 8px 12px;\"&gt;%appointment_date_time%&lt;/td&gt;</p><p>&nbsp;&lt;/tr&gt;</p><p>&nbsp;&lt;tr&gt;</p><p>&nbsp;&nbsp;&lt;td style=\"padding: 8px 12px; font-weight:bold; background:#f5f5f5;\"&gt;Duration&lt;/td&gt;</p><p>&nbsp;&nbsp;&lt;td style=\"padding: 8px 12px;\"&gt;%appointment_duration%&lt;/td&gt;</p><p>&nbsp;&lt;/tr&gt;</p><p>&nbsp;&lt;tr&gt;</p><p>&nbsp;&nbsp;&lt;td style=\"padding: 8px 12px; font-weight:bold; background:#f5f5f5;\"&gt;Status&lt;/td&gt;</p><p>&nbsp;&nbsp;&lt;td style=\"padding: 8px 12px;\"&gt;%appointment_status%&lt;/td&gt;</p><p>&nbsp;&lt;/tr&gt;</p><p>&nbsp;&lt;tr&gt;</p><p>&nbsp;&nbsp;&lt;td style=\"padding: 8px 12px; font-weight:bold; background:#f5f5f5;\"&gt;Location&lt;/td&gt;</p><p>&nbsp;&nbsp;&lt;td style=\"padding: 8px 12px;\"&gt;%location_name% — %location_address%&lt;/td&gt;</p><p>&nbsp;&lt;/tr&gt;</p><p>&lt;/table&gt;</p><p><br></p><p><br></p><p>&lt;p&gt;Need to make changes in the meantime?&lt;br&gt;</p><p>&lt;a href=\"%appointment_cancel_url%\"&gt;Manage / Cancel Appointment&lt;/a&gt;&lt;/p&gt;</p><p><br></p><p>&lt;p&gt;Thank you for your patience!&lt;/p&gt;</p><p><br></p><p>&lt;p&gt;Warm regards,&lt;br&gt;</p><p>&lt;strong&gt;%company_name%&lt;/strong&gt;&lt;br&gt;</p><p>&lt;/p&gt;</p><p>```</p><p><br></p>',NULL,'0',NULL,NULL);
INSERT INTO `wp_amelia_notifications` (`id`,`name`,`customName`,`status`,`type`,`entity`,`time`,`timeBefore`,`timeAfter`,`sendTo`,`subject`,`content`,`translations`,`sendOnlyMe`,`whatsAppTemplate`,`minimumTimeBeforeBooking`) VALUES('3','customer_appointment_rejected',NULL,'enabled','email','appointment',NULL,NULL,NULL,'customer','[{site_name}] {appointment_status}: {service_name} on {appointment_date} at {appointment_time}','<p>Dear <strong>%customer_full_name%</strong>,</p><p><br></p><p>Your <strong>%service_name%</strong> appointment, scheduled on <strong>%appointment_date_time%</strong> at <strong>%location_address% </strong>has been rejected.</p><p><br></p><p>Thank you for choosing our company, </p><p><strong>%company_name%</strong></p>',NULL,'0',NULL,NULL);
INSERT INTO `wp_amelia_notifications` (`id`,`name`,`customName`,`status`,`type`,`entity`,`time`,`timeBefore`,`timeAfter`,`sendTo`,`subject`,`content`,`translations`,`sendOnlyMe`,`whatsAppTemplate`,`minimumTimeBeforeBooking`) VALUES('4','customer_appointment_canceled',NULL,'enabled','email','appointment',NULL,NULL,NULL,'customer','Education Platform: Canceled — %service_name% on %appointment_date% at %appointment_start_time%','<p>&lt;p&gt;Dear &lt;strong&gt;%customer_full_name%&lt;/strong&gt;,&lt;/p&gt;</p><p><br></p><p>&lt;p&gt;Your appointment has been &lt;strong&gt;canceled&lt;/strong&gt; as requested. Here is a summary of the canceled booking for your records:&lt;/p&gt;</p><p><br></p><p>&lt;table style=\"width:100%; border-collapse:collapse; margin: 16px 0;\"&gt;</p><p>&nbsp;&lt;tr&gt;</p><p>&nbsp;&nbsp;&lt;td style=\"padding: 8px 12px; font-weight:bold; width:40%; background:#f5f5f5;\"&gt;Service&lt;/td&gt;</p><p>&nbsp;&nbsp;&lt;td style=\"padding: 8px 12px;\"&gt;%service_name%&lt;/td&gt;</p><p>&nbsp;&lt;/tr&gt;</p><p>&nbsp;&lt;tr&gt;</p><p>&nbsp;&nbsp;&lt;td style=\"padding: 8px 12px; font-weight:bold; background:#f5f5f5;\"&gt;Instructor&lt;/td&gt;</p><p>&nbsp;&nbsp;&lt;td style=\"padding: 8px 12px;\"&gt;%employee_full_name%&lt;/td&gt;</p><p>&nbsp;&lt;/tr&gt;</p><p>&nbsp;&lt;tr&gt;</p><p>&nbsp;&nbsp;&lt;td style=\"padding: 8px 12px; font-weight:bold; background:#f5f5f5;\"&gt;Date &amp;amp; Time&lt;/td&gt;</p><p>&nbsp;&nbsp;&lt;td style=\"padding: 8px 12px;\"&gt;%appointment_date_time%&lt;/td&gt;</p><p>&nbsp;&lt;/tr&gt;</p><p>&nbsp;&lt;tr&gt;</p><p>&nbsp;&nbsp;&lt;td style=\"padding: 8px 12px; font-weight:bold; background:#f5f5f5;\"&gt;Duration&lt;/td&gt;</p><p>&nbsp;&nbsp;&lt;td style=\"padding: 8px 12px;\"&gt;%appointment_duration%&lt;/td&gt;</p><p>&nbsp;&lt;/tr&gt;</p><p>&nbsp;&lt;tr&gt;</p><p>&nbsp;&nbsp;&lt;td style=\"padding: 8px 12px; font-weight:bold; background:#f5f5f5;\"&gt;Status&lt;/td&gt;</p><p>&nbsp;&nbsp;&lt;td style=\"padding: 8px 12px;\"&gt;%appointment_status%&lt;/td&gt;</p><p>&nbsp;&lt;/tr&gt;</p><p>&lt;/table&gt;</p><p><br></p><p>&lt;p&gt;If you have any questions about your cancellation or a potential refund, please contact us at &lt;a href=\"mailto:%company_email%\"&gt;%company_email%&lt;/a&gt; or %company_phone%.&lt;/p&gt;</p><p><br></p><p>&lt;p&gt;We\'d love to have you back — book a new session anytime:&lt;br&gt;</p><p><br></p><p>&lt;p&gt;We hope to see you again soon.&lt;/p&gt;</p><p><br></p><p>&lt;p&gt;Warm regards,&lt;br&gt;</p><p>&lt;strong&gt;%company_name%&lt;/strong&gt;&lt;br&gt;</p><p><br></p>',NULL,'0',NULL,NULL);
INSERT INTO `wp_amelia_notifications` (`id`,`name`,`customName`,`status`,`type`,`entity`,`time`,`timeBefore`,`timeAfter`,`sendTo`,`subject`,`content`,`translations`,`sendOnlyMe`,`whatsAppTemplate`,`minimumTimeBeforeBooking`) VALUES('5','customer_appointment_rescheduled',NULL,'enabled','email','appointment',NULL,NULL,NULL,'customer','[{site_name}] {appointment_status}: {service_name} on {appointment_date} at {appointment_time}','<p>Dear <strong>%customer_full_name%</strong>,</p><p><br></p><p>The details for your <strong>%service_name%</strong> appointment with <strong>%employee_full_name%</strong> at <strong>%location_name%</strong> has been changed. The appointment is now set for <strong>%appointment_date%</strong> at <strong>%appointment_start_time%</strong>.</p><p><br></p><p>Thank you for choosing our company,</p><p><strong>%company_name%</strong></p><p><br></p><p><span class=\"ql-cursor\">﻿</span>Zoom Link - %zoom_join_url_date_time%</p>',NULL,'0',NULL,NULL);
INSERT INTO `wp_amelia_notifications` (`id`,`name`,`customName`,`status`,`type`,`entity`,`time`,`timeBefore`,`timeAfter`,`sendTo`,`subject`,`content`,`translations`,`sendOnlyMe`,`whatsAppTemplate`,`minimumTimeBeforeBooking`) VALUES('6','customer_appointment_next_day_reminder',NULL,'enabled','email','appointment','17:00:00',NULL,NULL,'customer','[{site_name}] {appointment_status}: {service_name} on {appointment_date} at {appointment_time}','<p>Dear <strong>%customer_full_name%</strong>,</p><p><br></p><p>We would like to remind you that you have <strong>%service_name%</strong> appointment tomorrow at <strong>%appointment_start_time%</strong>. We are waiting for you at <strong>%location_name%</strong>.</p><p><br></p><p>Thank you for choosing our company,</p><p><strong>%company_name%</strong></p><p><br></p><p><span class=\"ql-cursor\">﻿</span>Zoom Link - %zoom_join_url_date_time%</p>',NULL,'0',NULL,NULL);
INSERT INTO `wp_amelia_notifications` (`id`,`name`,`customName`,`status`,`type`,`entity`,`time`,`timeBefore`,`timeAfter`,`sendTo`,`subject`,`content`,`translations`,`sendOnlyMe`,`whatsAppTemplate`,`minimumTimeBeforeBooking`) VALUES('7','customer_appointment_follow_up',NULL,'enabled','email','appointment',NULL,NULL,'1800','customer','[{site_name}] {appointment_status}: {service_name} on {appointment_date} at {appointment_time}','<p>Dear <strong>%customer_full_name%</strong>,</p><p><br></p><p>Thank you once again for choosing our company. We hope you were satisfied with your <strong>%service_name%</strong>.</p><p><br></p><p>We look forward to seeing you again soon,</p><p><strong>%company_name%</strong></p>',NULL,'0',NULL,NULL);
INSERT INTO `wp_amelia_notifications` (`id`,`name`,`customName`,`status`,`type`,`entity`,`time`,`timeBefore`,`timeAfter`,`sendTo`,`subject`,`content`,`translations`,`sendOnlyMe`,`whatsAppTemplate`,`minimumTimeBeforeBooking`) VALUES('8','customer_birthday_greeting',NULL,'enabled','email','appointment','17:00:00',NULL,NULL,'customer','Happy Birthday','Dear <strong>%customer_full_name%</strong>,<br><br>Happy birthday!<br>We wish you all the best.\n                    <br><br>Thank you for choosing our company,<br><strong>%company_name%</strong>',NULL,'0',NULL,NULL);
INSERT INTO `wp_amelia_notifications` (`id`,`name`,`customName`,`status`,`type`,`entity`,`time`,`timeBefore`,`timeAfter`,`sendTo`,`subject`,`content`,`translations`,`sendOnlyMe`,`whatsAppTemplate`,`minimumTimeBeforeBooking`) VALUES('9','provider_appointment_approved',NULL,'enabled','email','appointment',NULL,NULL,NULL,'provider','New Booking Approved: %service_name% with %customer_full_name% on %appointment_date% at %appointment_start_time%','<!-- Content --><p>Dear <strong>%employee_full_name%</strong>,</p><p>A new appointment has been <strong>approved</strong> and assigned to you. Please review the booking details below and ensure you are prepared for the session.</p><table style=\"width:100%; border-collapse:collapse; margin: 16px 0;\">  <tr>    <td style=\"padding: 8px 12px; font-weight:bold; width:40%; background:#f5f5f5;\">Student Name</td>    <td style=\"padding: 8px 12px;\">%customer_full_name%</td>  </tr>  <tr>    <td style=\"padding: 8px 12px; font-weight:bold; background:#f5f5f5;\">Student Email</td>    <td style=\"padding: 8px 12px;\"><a href=\"mailto:%customer_email%\">%customer_email%</a></td>  </tr>  <tr>    <td style=\"padding: 8px 12px; font-weight:bold; background:#f5f5f5;\">Student Phone</td>    <td style=\"padding: 8px 12px;\">%customer_phone%</td>  </tr>  <tr>    <td style=\"padding: 8px 12px; font-weight:bold; background:#f5f5f5;\">Service</td>    <td style=\"padding: 8px 12px;\">%service_name%</td>  </tr>  <tr>    <td style=\"padding: 8px 12px; font-weight:bold; background:#f5f5f5;\">Date &amp; Time</td>    <td style=\"padding: 8px 12px;\">%appointment_date_time%</td>  </tr>  <tr>    <td style=\"padding: 8px 12px; font-weight:bold; background:#f5f5f5;\">Duration</td>    <td style=\"padding: 8px 12px;\">%appointment_duration%</td>  </tr>  <tr>    <td style=\"padding: 8px 12px; font-weight:bold; background:#f5f5f5;\">Location</td>    <td style=\"padding: 8px 12px;\">%location_name% — %location_address%</td>  </tr>  <tr>    <td style=\"padding: 8px 12px; font-weight:bold; background:#f5f5f5;\">Number of Persons</td>    <td style=\"padding: 8px 12px;\">%number_of_persons%</td>  </tr>  <tr>    <td style=\"padding: 8px 12px; font-weight:bold; background:#f5f5f5;\">Payment Status</td>    <td style=\"padding: 8px 12px;\">%payment_type% — %appointment_price%</td>  </tr>  <tr>    <td style=\"padding: 8px 12px; font-weight:bold; background:#f5f5f5;\">Appointment Notes</td>    <td style=\"padding: 8px 12px;\">%appointment_notes%</td>  </tr>  <tr>    <td style=\"padding: 8px 12px; font-weight:bold; background:#f5f5f5;\">Zoom Link</td>    <td style=\"padding: 8px 12px;\"><a href=\"%zoom_host_url%\">%zoom_host_url%</a></td>  </tr></table><p>If you have any scheduling conflicts or concerns, please contact the admin team promptly at <a href=\"mailto:%company_email%\">%company_email%</a>.</p><p>Regards,<br><strong>%company_name%</strong></p>',NULL,'0',NULL,NULL);
INSERT INTO `wp_amelia_notifications` (`id`,`name`,`customName`,`status`,`type`,`entity`,`time`,`timeBefore`,`timeAfter`,`sendTo`,`subject`,`content`,`translations`,`sendOnlyMe`,`whatsAppTemplate`,`minimumTimeBeforeBooking`) VALUES('10','provider_appointment_pending',NULL,'enabled','email','appointment',NULL,NULL,NULL,'provider','%service_name% Appointment Pending','Hi <strong>%employee_full_name%</strong>,<br><br>You have new appointment \n                     in <strong>%service_name%</strong>. The appointment is waiting for a confirmation.<br><br>Thank \n                     you,<br><strong>%company_name%</strong>',NULL,'0',NULL,NULL);
INSERT INTO `wp_amelia_notifications` (`id`,`name`,`customName`,`status`,`type`,`entity`,`time`,`timeBefore`,`timeAfter`,`sendTo`,`subject`,`content`,`translations`,`sendOnlyMe`,`whatsAppTemplate`,`minimumTimeBeforeBooking`) VALUES('11','provider_appointment_rejected',NULL,'enabled','email','appointment',NULL,NULL,NULL,'provider','%service_name% Appointment Rejected','Hi <strong>%employee_full_name%</strong>,<br><br>Your <strong>%service_name%</strong> appointment \n                     at <strong>%location_name%</strong>, scheduled for <strong>%appointment_date%</strong> at  \n                     <strong>%appointment_start_time%</strong> has been rejected.\n                     <br><br>Thank you,<br><strong>%company_name%</strong>',NULL,'0',NULL,NULL);
