INSERT INTO `wp_amelia_notifications` (`id`,`name`,`customName`,`status`,`type`,`entity`,`time`,`timeBefore`,`timeAfter`,`sendTo`,`subject`,`content`,`translations`,`sendOnlyMe`,`whatsAppTemplate`,`minimumTimeBeforeBooking`) VALUES('29','customer_event_approved',NULL,'enabled','email','event',NULL,NULL,NULL,'customer','[{site_name}] Webinar confirmed: {event_name} — {event_start_date} {event_start_time}','<!-- Content --><p>Dear           <strong>%customer_full_name%</strong>,</p><p>          <br></p><p>You have successfully scheduled           <strong>%event_name%</strong> event. We are waiting you at           <strong>%event_location% </strong>on           <strong>%event_start_date_time%</strong>. </p><p>          <br></p><p>Thank you for choosing our company,</p><p>          <strong>%company_name%</strong></p>This email includes an .ics calendar file. Click “Add to Calendar” if your client supports it.<br> Zoom Link - %zoom_join_url%<br> Zoom Link - %zoom_host_url%',NULL,'0',NULL,NULL);
INSERT INTO `wp_amelia_notifications` (`id`,`name`,`customName`,`status`,`type`,`entity`,`time`,`timeBefore`,`timeAfter`,`sendTo`,`subject`,`content`,`translations`,`sendOnlyMe`,`whatsAppTemplate`,`minimumTimeBeforeBooking`) VALUES('30','customer_event_rejected',NULL,'enabled','email','event',NULL,NULL,NULL,'customer','%event_name% Event Canceled By Admin','Dear <strong>%customer_full_name%</strong>,<br><br>Your <strong>%event_name%</strong>\n                     event, scheduled on <strong>%event_start_date_time%</strong> at <strong>%event_location%\n                     </strong>has been canceled.<br><br>Thank you for choosing our company,\n                     <br><strong>%company_name%</strong>',NULL,'0',NULL,NULL);
