INSERT INTO `wp_amelia_notifications` (`id`,`name`,`customName`,`status`,`type`,`entity`,`time`,`timeBefore`,`timeAfter`,`sendTo`,`subject`,`content`,`translations`,`sendOnlyMe`,`whatsAppTemplate`,`minimumTimeBeforeBooking`) VALUES('32','customer_event_rescheduled',NULL,'enabled','email','event',NULL,NULL,NULL,'customer','%event_name% Event Rescheduled','<p>Dear <strong>%customer_full_name%</strong>,</p><p><br></p><p>The details for your <strong>%event_name%</strong> event at <strong>%event_location%</strong> has been changed. The event is now set for <strong>%event_start_date_time%</strong>.</p><p><br></p><p> Thank you for choosing our company,</p><p><strong>%company_name%</strong></p><p><br></p><p><span class=\"ql-cursor\">﻿</span>Zoom Link - %zoom_join_url_date_time%</p>',NULL,'0',NULL,NULL);
