INSERT INTO `wp_amelia_notifications` (`id`,`name`,`customName`,`status`,`type`,`entity`,`time`,`timeBefore`,`timeAfter`,`sendTo`,`subject`,`content`,`translations`,`sendOnlyMe`,`whatsAppTemplate`,`minimumTimeBeforeBooking`) VALUES('106','customer_appointment_updated',NULL,'enabled','email','appointment',NULL,NULL,NULL,'customer','[{site_name}] {appointment_status}: {service_name} on {appointment_date} at {appointment_time}','<p>Dear <strong>%customer_full_name%</strong>,</p><p><br></p><p>Details of the appointment on <strong>%appointment_date_time%</strong> have changed:</p><p><br></p><p><br></p><ul><li>Employee: <strong>%employee_full_name%</strong></li><li>Location: <strong>%location_name%</strong></li><li>Extras: <strong>%service_extras%</strong></li></ul><p><br></p><p>Thank you for choosing our company,</p><p><strong>%company_name%</strong></p><p><br></p><p><span class=\"ql-cursor\">﻿</span>Zoom Link - %zoom_join_url_date_time%</p>',NULL,'0',NULL,NULL);
INSERT INTO `wp_amelia_notifications` (`id`,`name`,`customName`,`status`,`type`,`entity`,`time`,`timeBefore`,`timeAfter`,`sendTo`,`subject`,`content`,`translations`,`sendOnlyMe`,`whatsAppTemplate`,`minimumTimeBeforeBooking`) VALUES('107','provider_appointment_updated',NULL,'enabled','email','appointment',NULL,NULL,NULL,'provider','[{site_name}] {appointment_status}: {service_name} on {appointment_date} at {appointment_time}','<p>Hi <strong>%employee_full_name%</strong>,</p><p><br></p><p>Details of the appointment on <strong>%appointment_date_time%</strong> have changed: </p><ul><li>Customers: <strong>%customer_full_name%</strong></li><li>Location: <strong>%location_name%</strong></li><li>Extras: <strong>%service_extras%</strong></li></ul><p><br></p><p>Thank you,</p><p><strong>%company_name%</strong></p>',NULL,'0',NULL,NULL);
