INSERT INTO `wp_amelia_notifications` (`id`,`name`,`customName`,`status`,`type`,`entity`,`time`,`timeBefore`,`timeAfter`,`sendTo`,`subject`,`content`,`translations`,`sendOnlyMe`,`whatsAppTemplate`,`minimumTimeBeforeBooking`) VALUES('118','customer_invoice',NULL,'enabled','email','appointment',NULL,NULL,NULL,'customer','Booking Invoice','Dear <strong>%customer_full_name%</strong>,<br><br>Please find the attached invoice for your reference. If you have any questions, feel free to contact us.\n                    <br><br>Thank you for choosing our company, <br>\n                    <strong>%company_name%</strong>',NULL,'0',NULL,NULL);
INSERT INTO `wp_amelia_notifications` (`id`,`name`,`customName`,`status`,`type`,`entity`,`time`,`timeBefore`,`timeAfter`,`sendTo`,`subject`,`content`,`translations`,`sendOnlyMe`,`whatsAppTemplate`,`minimumTimeBeforeBooking`) VALUES('119','customer_event_qr_code',NULL,'enabled','email','event',NULL,NULL,NULL,'customer','E-Ticket for %event_name%','Dear <strong>%customer_full_name%</strong>,<br><br>\n                 Thank you for registering for \n                 <strong>%event_name%</strong> on \n                 <strong>%event_start_date_time%</strong>.<br><br>\n                 Please save the following E-Ticket on your mobile phone and present it upon arrival.<br><br>\n                 We are waiting for you at <strong>%event_location%</strong>.<br><br>\n                 Thank you for choosing our company,<br><strong>%company_name%</strong>',NULL,'0',NULL,NULL);
INSERT INTO `wp_amelia_notifications` (`id`,`name`,`customName`,`status`,`type`,`entity`,`time`,`timeBefore`,`timeAfter`,`sendTo`,`subject`,`content`,`translations`,`sendOnlyMe`,`whatsAppTemplate`,`minimumTimeBeforeBooking`) VALUES('120','customer_appointment_waiting',NULL,'enabled','email','appointment',NULL,NULL,NULL,'customer','%service_name% Waiting List joined','Dear <strong>%customer_full_name%</strong>,<br><br>You have successfully joined the Waiting List for the\n                 <strong>%service_name%</strong> service at\n                 <strong>%location_address%</strong> on\n                 <strong>%appointment_date_time%</strong>.<br><br>\n                 Thank you for choosing our company,<br><strong>%company_name%</strong>',NULL,'0',NULL,NULL);
INSERT INTO `wp_amelia_notifications` (`id`,`name`,`customName`,`status`,`type`,`entity`,`time`,`timeBefore`,`timeAfter`,`sendTo`,`subject`,`content`,`translations`,`sendOnlyMe`,`whatsAppTemplate`,`minimumTimeBeforeBooking`) VALUES('121','customer_appointment_waiting',NULL,'enabled','sms','appointment',NULL,NULL,NULL,'customer','%event_name% Waiting List joined','Dear %customer_full_name%,\n                \nYou have successfully joined the Waiting List for the\n%service_name% service at %location_address% on %appointment_date_time%.\n                \nThank you for choosing our company,\n%company_name%',NULL,'0',NULL,NULL);
INSERT INTO `wp_amelia_notifications` (`id`,`name`,`customName`,`status`,`type`,`entity`,`time`,`timeBefore`,`timeAfter`,`sendTo`,`subject`,`content`,`translations`,`sendOnlyMe`,`whatsAppTemplate`,`minimumTimeBeforeBooking`) VALUES('122','customer_appointment_waiting_available_spot',NULL,'enabled','email','appointment',NULL,NULL,NULL,'customer','A Spot Just Opened Up for %service_name% ','Dear <strong>%customer_full_name%</strong>,<br><br> Good news! A spot has just become available for\n                 <strong>%service_name%</strong> on\n                 <strong>%appointment_date_time%</strong>.<br><br>\n                 You’re on the waiting list, and now is your chance to confirm your booking before it’s taken by someone else.<br><br>\n                 <a href=\"%appointment_approve_url%\">Confirm My Appointment</a><br><br>\n                 Thank you for choosing our company,<br><strong>%company_name%</strong>',NULL,'0',NULL,NULL);
INSERT INTO `wp_amelia_notifications` (`id`,`name`,`customName`,`status`,`type`,`entity`,`time`,`timeBefore`,`timeAfter`,`sendTo`,`subject`,`content`,`translations`,`sendOnlyMe`,`whatsAppTemplate`,`minimumTimeBeforeBooking`) VALUES('123','customer_appointment_waiting_available_spot',NULL,'enabled','sms','appointment',NULL,NULL,NULL,'customer','A Spot Just Opened Up for %service_name%','Dear %customer_full_name%,\n\nGood news! A spot has just become available for\n%service_name% on %appointment_date_time%.\n                 \nYou’re on the waiting list, and now is your chance to confirm your booking before it’s taken by someone else.\n<a href=\"%appointment_approve_url%\">Confirm My Appointment</a>\n                 \nThank you for choosing our company,\n%company_name%',NULL,'0',NULL,NULL);
INSERT INTO `wp_amelia_notifications` (`id`,`name`,`customName`,`status`,`type`,`entity`,`time`,`timeBefore`,`timeAfter`,`sendTo`,`subject`,`content`,`translations`,`sendOnlyMe`,`whatsAppTemplate`,`minimumTimeBeforeBooking`) VALUES('124','provider_appointment_waiting',NULL,'enabled','email','appointment',NULL,NULL,NULL,'provider','%service_name% Waiting List joined','Hi <strong>%employee_full_name%</strong>,<br><br>A new attendee has been added to the waiting list for\n                 <strong>%service_name%</strong> Service at\n                 <strong>%location_address%</strong> on\n                 <strong>%appointment_date_time%</strong>.<br><br>\n                 Thank you,<br><strong>%company_name%</strong>',NULL,'0',NULL,NULL);
